        rankChipStyle = (Color.FromHex((ReadOnlySpan<char>) "#3A2A2066", new Color?()), Color.FromHex((ReadOnlySpan<char>) "#C49157", new Color?()));
        break;
      default:
        rankChipStyle = !isCurrentPlayer ? (Color.FromHex((ReadOnlySpan<char>) "#1D222B66", new Color?()), Color.FromHex((ReadOnlySpan<char>) "#4A505C", new Color?())) : (Color.FromHex((ReadOnlySpan<char>) "#203D2866", new Color?()), Color.FromHex((ReadOnlySpan<char>) "#6EC07A", new Color?()));
        break;
    }
    return rankChipStyle;
  }

  private Color GetRowBackgroundColor(int rank, bool isCurrentPlayer)
  {
    if (isCurrentPlayer)
      return Color.FromHex((ReadOnlySpan<char>) "#1E352466", new Color?());
    Color rowBackgroundColor;
    switch (rank)
    {
      case 1:
        rowBackgroundColor = Color.FromHex((ReadOnlySpan<char>) "#2E261266", new Color?());
        break;
      case 2:
        rowBackgroundColor = Color.FromHex((ReadOnlySpan<char>) "#242A3666", new Color?());
        break;
      case 3:
        rowBackgroundColor = Color.FromHex((ReadOnlySpan<char>) "#2D211B66", new Color?());
        break;
      default:
        rowBackgroundColor = rank % 2 == 0 ? Color.FromHex((ReadOnlySpan<char>) "#171A2244", new Color?()) : Color.FromHex((ReadOnlySpan<char>) "#12151C44", new Color?());
        break;
    }
    return rowBackgroundColor;
  }

  private string FormatSurvivalTime(int seconds)
  {
    int num1 = seconds / 3600;
    int num2 = seconds % 3600 / 60;
    int num3 = seconds % 60;
    if (num1 > 0)
      return $"{num1}:{num2:D2}:{num3:D2}";
    return $"{num2}:{num3:D2}";
  }

  private string FormatKd(int kills, int deaths)
  {
    return $"{(deaths > 0 ? (float) kills / (float) deaths : (float) kills):0.00}";
  }

  private void UpdateSummaryStats(
    string rankValue,
    string ratingValue,
    string kdValue,
    string winsValue)
  {
    this.SummaryRankLabel.Text = Loc.GetString("pubg-leaderboard-summary-rank", new (string, object)[1]
    {
      ("value", (object) rankValue)
    });
    this.SummaryRatingLabel.Text = Loc.GetString("pubg-leaderboard-summary-rating", new (string, object)[1]
    {
      ("value", (object) ratingValue)
    });
    this.SummaryKdLabel.Text = Loc.GetString("pubg-leaderboard-summary-kd", new (string, object)[1]
    {
      ("value", (object) kdValue)
    });
    this.SummaryWinsLabel.Text = Loc.GetString("pubg-leaderboard-summary-wins", new (string, object)[1]
    {
      ("value", (object) winsValue)
    });
  }

  private void UpdatePlayerPosition(LeaderboardResponseMessage msg)
  {
    LeaderboardEntry leaderboardEntry = msg.Players.FirstOrDefault<LeaderboardEntry>((Func<LeaderboardEntry, bool>) (p => p.Username.Equals(msg.PlayerUsername, StringComparison.OrdinalIgnoreCase)));
    if (msg.PlayerRank > 0)
    {
      if (leaderboardEntry != null)
      {
        this.PlayerPositionLabel.Text = Loc.GetString("pubg-leaderboard-you-in-top", new (string, object)[1]
        {
          ("rank", (object) msg.PlayerRank)
        });
        this.PlayerPositionLabel.FontColorOverride = new Color?(Color.Gold);
      }
      else
      {
        this.PlayerPositionLabel.Text = Loc.GetString("pubg-leaderboard-your-rank", new (string, object)[2]
        {
          ("rank", (object) msg.PlayerRank),
          ("total", (object) msg.TotalPlayers)
        });
        this.PlayerPositionLabel.FontColorOverride = new Color?(Color.White);
      }
      this.PlayerPositionDetails.Text = Loc.GetString("pubg-leaderboard-your-rating", new (string, object)[1]
      {
        ("rating", (object) msg.PlayerRating)
      });
      string kdValue = leaderboardEntry != null ? this.FormatKd(leaderboardEntry.Kills, leaderboardEntry.Deaths) : "-";
      string winsValue = leaderboardEntry != null ? leaderboardEntry.Wins.ToString() : "-";
      this.UpdateSummaryStats($"#{msg.PlayerRank}", msg.PlayerRating.ToString(), kdValue, winsValue);
    }
    else
    {
      this.PlayerPositionLabel.Text = Loc.GetString("pubg-leaderboard-not-ranked");
      this.PlayerPositionLabel.FontColorOverride = new Color?(Color.Gray);
      this.PlayerPositionDetails.Text = Loc.GetString("pubg-leaderboard-play-to-rank");
      this.UpdateSummaryStats("-", "-", "-", "-");
    }
  }

